('business:5-5-cash-and-cash-flow:match:7971503d', 'business', 'business:5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Cash Flow Forecast”?", "options": ["Total inflow minus total outflow for a given period.", "The amount of cash available at the beginning of the month; equal to the previous month''s closing balance.", "The amount of cash left at the end of the month; becomes the opening balance for the next month.", "A statement showing the expected flow of money into and out of a business over a period of time."]}'::jsonb, '{"answer": 3, "explain": "“Cash Flow Forecast” means: A statement showing the expected flow of money into and out of a business over a period of time."}'::jsonb),
('business:5-5-cash-and-cash-flow:match:cd54f93c', 'business', 'business:5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Net Cash Flow”?", "options": ["The amount of cash available at the beginning of the month; equal to the previous month''s closing balance.", "The amount of cash left at the end of the month; becomes the opening balance for the next month.", "The ability of a business to pay its short-term debts which must be paid in the near future.", "Total inflow minus total outflow for a given period."]}'::jsonb, '{"answer": 3, "explain": "“Net Cash Flow” means: Total inflow minus total outflow for a given period."}'::jsonb),
('business:5-5-cash-and-cash-flow:match:49a3b2f3', 'business', 'business:5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Opening Balance”?", "options": ["The amount of cash left at the end of the month; becomes the opening balance for the next month.", "The ability of a business to pay its short-term debts which must be paid in the near future.", "When more cash flows into the business than flows out during a month (a cash flow surplus).", "The amount of cash available at the beginning of the month; equal to the previous month''s closing balance."]}'::jsonb, '{"answer": 3, "explain": "“Opening Balance” means: The amount of cash available at the beginning of the month; equal to the previous month''s closing balance."}'::jsonb),
('business:5-5-cash-and-cash-flow:match:5a17a7f6', 'business', 'business:5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Closing Balance”?", "options": ["The ability of a business to pay its short-term debts which must be paid in the near future.", "When more cash flows into the business than flows out during a month (a cash flow surplus).", "The amount of cash left at the end of the month; becomes the opening balance for the next month.", "When more cash flows out of the business than flows in during a month (a cash flow deficit)."]}'::jsonb, '{"answer": 2, "explain": "“Closing Balance” means: The amount of cash left at the end of the month; becomes the opening balance for the next month."}'::jsonb),
('business:5-5-cash-and-cash-flow:match:b30d9314', 'business', 'business:5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Liquidity”?", "options": ["When more cash flows into the business than flows out during a month (a cash flow surplus).", "When more cash flows out of the business than flows in during a month (a cash flow deficit).", "Money held in bank accounts and on the premises; not simply notes and coins.", "The ability of a business to pay its short-term debts which must be paid in the near future."]}'::jsonb, '{"answer": 3, "explain": "“Liquidity” means: The ability of a business to pay its short-term debts which must be paid in the near future."}'::jsonb),
('business:5-5-cash-and-cash-flow:match:99777cac', 'business', 'business:5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Positive Cash Flow”?", "options": ["When more cash flows out of the business than flows in during a month (a cash flow deficit).", "Money held in bank accounts and on the premises; not simply notes and coins.", "Revenue received by a business minus the total costs of running the business.", "When more cash flows into the business than flows out during a month (a cash flow surplus)."]}'::jsonb, '{"answer": 3, "explain": "“Positive Cash Flow” means: When more cash flows into the business than flows out during a month (a cash flow surplus)."}'::jsonb)
